// OJ-Calcom-Booking-Sink (OJ-FUNNEL B3, 2026-07-19)
// Receives cal.com webhook events for the OJ strategy-call slug + writes structured
// oj_strategy_call_booked events, closing the report->booked measurement gap.
// Cal.com sends triggerEvent in {BOOKING_CREATED | BOOKING_CANCELLED | BOOKING_RESCHEDULED}.
const OJ_URL='https://wwacjhkpuaiijbkqnhsi.supabase.co';
const OJ_KEY='eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Ind3YWNqaGtwdWFpaWpia3FuaHNpIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3ODgwODQyNSwiZXhwIjoyMDk0Mzg0NDI1fQ.I92OcFBQ9lxs4hFH3Q_rWYup2bULHuL3a2rqeEb1xf0';
const H={apikey:OJ_KEY,Authorization:'Bearer '+OJ_KEY,'Content-Type':'application/json'};
const body=$input.item.json.body||$input.item.json||{};
const trg=(body.triggerEvent||'').toLowerCase();
const p=body.payload||{};
const email=((p.attendees&&p.attendees[0]&&p.attendees[0].email)||p.email||'').toLowerCase();
const startTime=p.startTime||p.start||null;
const eventType='oj_strategy_call_'+(trg.includes('cancel')?'cancelled':trg.includes('reschedul')?'rescheduled':'booked');
const payload={src:'calcom',trigger:trg,email:email,start_time:startTime,event_type_slug:p.eventTypeSlug||p.eventType||null,booking_uid:p.uid||null,title:p.title||null};
await this.helpers.httpRequest({method:'POST',url:OJ_URL+'/rest/v1/events',
  headers:{...H,Prefer:'return=minimal'},body:{event_type:eventType,actor:'system',payload:payload},json:true});
return [{json:{ok:true,event_type:eventType,email}}];
